import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"Token 预算管理 (Token Management)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/token-management.md","filePath":"user-guide/tools/llm-chat/context-pipeline/token-management.md","lastUpdated":1779185013000}'),r={name:"user-guide/tools/llm-chat/context-pipeline/token-management.md"};function i(l,e,s,h,d,k){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="token-预算管理-token-management" tabindex="-1">Token 预算管理 (Token Management) <a class="header-anchor" href="#token-预算管理-token-management" aria-label="Permalink to &quot;Token 预算管理 (Token Management)&quot;">​</a></h1><p>Token 是 LLM 处理文本的计费和性能单位。有效的 Token 管理不仅能节省成本，还能防止上下文溢出导致模型“断片”。</p><h2 id="_1-token-limiter-处理器" tabindex="-1">1. Token Limiter 处理器 <a class="header-anchor" href="#_1-token-limiter-处理器" aria-label="Permalink to &quot;1. Token Limiter 处理器&quot;">​</a></h2><p><strong>Token Limiter</strong> 是管道中最重要的处理器之一。它负责计算当前上下文的总 Token 数，并在超过模型限制时执行裁剪。</p><h3 id="裁剪优先级-priority" tabindex="-1">裁剪优先级 (Priority) <a class="header-anchor" href="#裁剪优先级-priority" aria-label="Permalink to &quot;裁剪优先级 (Priority)&quot;">​</a></h3><p>当上下文超长时，处理器不会随机删除内容，而是按照以下优先级进行保留：</p><ol><li><strong>核心预设 (Presets)</strong>: 系统提示词等核心设定具有最高优先级，最后被裁剪。</li><li><strong>世界书与知识库</strong>: 动态注入的内容次之。</li><li><strong>历史消息 (History)</strong>: 按照“由近及远”的原则，最先裁剪最早的历史消息。</li></ol><h2 id="_2-统计与显示" tabindex="-1">2. 统计与显示 <a class="header-anchor" href="#_2-统计与显示" aria-label="Permalink to &quot;2. 统计与显示&quot;">​</a></h2><p>在聊天界面的侧边栏或<a href="./analyzer">上下文分析器</a>中，你可以看到实时的 Token 统计：</p><ul><li><strong>当前 Token</strong>: 本次请求预估消耗的 Token 总数。</li><li><strong>上下文占比</strong>: 核心预设、历史消息、世界书等各部分占用的比例。</li></ul><h2 id="_3-优化建议" tabindex="-1">3. 优化建议 <a class="header-anchor" href="#_3-优化建议" aria-label="Permalink to &quot;3. 优化建议&quot;">​</a></h2><h3 id="_3-1-使用上下文压缩" tabindex="-1">3.1 使用上下文压缩 <a class="header-anchor" href="#_3-1-使用上下文压缩" aria-label="Permalink to &quot;3.1 使用上下文压缩&quot;">​</a></h3><p>当对话过长时，与其任由系统裁剪掉早期的关键信息，不如使用<a href="./context-compression">上下文压缩</a>。</p><ul><li><strong>原理</strong>: 调用模型将一段长对话总结为几句话。</li><li><strong>效果</strong>: 原始消息被移除，摘要消息被注入，大幅释放 Token 空间。</li></ul><h3 id="_3-2-调整扫描深度" tabindex="-1">3.2 调整扫描深度 <a class="header-anchor" href="#_3-2-调整扫描深度" aria-label="Permalink to &quot;3.2 调整扫描深度&quot;">​</a></h3><p>减小<a href="./../worldbook/scanning-strategy">世界书</a>或知识库的扫描深度和召回上限，可以有效控制单次请求的 Token 基础开销。</p><h3 id="_3-3-启用-token-截断警告" tabindex="-1">3.3 启用 Token 截断警告 <a class="header-anchor" href="#_3-3-启用-token-截断警告" aria-label="Permalink to &quot;3.3 启用 Token 截断警告&quot;">​</a></h3><p>在系统设置中，你可以配置当 Token 接近模型上限时显示警告，提醒你进行手动清理或压缩。</p><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./context-compression">上下文压缩指南</a></li><li><a href="./analyzer">上下文分析器</a></li><li><a href="./../agents/parameters#4-模型高级参数">模型参数配置</a></li></ul>',21)])])}const p=a(r,[["render",i]]);export{c as __pageData,p as default};
